// APIError carries HTTP status information for structured exit codes.
type APIError struct {
	Method     string
	Path       string
	StatusCode int
	Body       string
}

func (e *APIError) Error() string {
	return fmt.Sprintf("%s %s returned HTTP %d: %s", e.Method, e.Path, e.StatusCode, e.Body)
}

func newHTTPClient(timeout time.Duration, jar http.CookieJar) *http.Client {
	builder := surf.NewClient().
		Builder().
		Impersonate().
		Chrome().
		Timeout(timeout)
	if jar == nil {
		builder = builder.Session()
	}
	surfClient := builder.Build().Unwrap()
	httpClient := surfClient.Std()
	httpClient.Timeout = timeout
	if jar != nil {
		httpClient.Jar = jar
	}
	return httpClient
}

func New(cfg *config.Config, timeout time.Duration, rateLimit float64) *Client {
	homeDir, _ := os.UserHomeDir()
	cacheDir := filepath.Join(homeDir, ".cache", "skool-pp-cli")
	httpClient := newHTTPClient(timeout, nil)
	authCookie := ""
	if cfg != nil {
		authCookie = cfg.AuthHeader()
	}
	resolver := skoolclient.NewResolver(httpClient, "", authCookie, filepath.Join(cacheDir, "buildid.cache"))
	return &Client{
		BaseURL:       strings.TrimRight(cfg.BaseURL, "/"),
		Config:        cfg,
		HTTPClient:    httpClient,
		cacheDir:      cacheDir,
		limiter:       cliutil.NewAdaptiveLimiter(rateLimit),
		buildResolver: resolver,
	}
}

// ensureBuildID lazy-resolves Skool's rotating Next.js buildId when a path
// requires it. Safe to call on every request — fast path returns immediately
// if buildId is already populated. The community slug is read from
// Config.TemplateVars["community"] or, when absent, defaults to whatever
// community is reachable; the buildId is global to skool.com.
func (c *Client) ensureBuildID(path string) error {
	if c.buildResolver == nil {
		return nil
	}
	if !strings.Contains(path, "{buildId}") {
		return nil
	}
	if c.Config != nil && c.Config.TemplateVars["buildId"] != "" {
		return nil
	}
	community := ""
	if c.Config != nil {
		community = c.Config.TemplateVars["community"]
	}
	id, err := c.buildResolver.Resolve(context.Background(), community)
	if err != nil {
		return err
	}
	if c.Config != nil {
		if c.Config.TemplateVars == nil {
			c.Config.TemplateVars = map[string]string{}
		}
		c.Config.TemplateVars["buildId"] = id
	}
	return nil
}

// InvalidateBuildID clears the cached buildId on stale-data signals (HTTP 404
// from a Next.js data route is the canonical trigger).
func (c *Client) InvalidateBuildID() {
	if c.buildResolver != nil {
		c.buildResolver.Invalidate()
	}
	if c.Config != nil {
		delete(c.Config.TemplateVars, "buildId")
	}
}

